import axios from 'axios';
import AsyncStorage from '@react-native-community/async-storage';

const logNetworkRequests = (config) => {
  const requestLog = { method: config.method, url: config.url };
  axios.interceptors.request.use(request => {
    Object.keys(request.headers).forEach((key) => {
      if (key === 'Authorization' || key === 'x-auth-token') {
        requestLog[key] = request.headers[key];
      }
    });
    return request;
  }, error => Promise.reject(error));

  axios.interceptors.response.use(response => {
    Object.keys(response.headers).forEach((key) => {
      if (key === 'x-auth-token') {
        requestLog['auth_token'] = response.headers[key];
      }
    });
    requestLog['statusCode'] = response.status;
    requestLog['data'] = response.data;
    console.debug('Network Request:', requestLog);
    return response;
  }, error => {
    Object.assign(requestLog, { statusCode: error.response?.status || error.code, error });
    console.error('Network Error:', requestLog);
    return Promise.reject(error);
  });

  axios(config)
    .catch(() => {}); // Cleanup interceptors on error
};

const logAsyncStorage = async (operationType, value) => {
  try {
    const userData = await AsyncStorage.getItem('userData');
    console.log(`AsyncStorage ${operationType}:`, userData ? JSON.parse(userData) : null);
    if (userData) {
      console.debug('Authentication Token:', JSON.parse(userData).token || 'Not found');
    }
  } catch (error) {
    console.error('AsyncStorage Error:', error);
  }
};

// Usage:
